import { Toggle as TogglePrimitive, ToggleContext, useToggleContext } from '@ark-ui/react/toggle';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Toggle.module.css';

type ToggleVariant = 'default' | 'outline' | 'ghost';
type ToggleSize = 'xs' | 'sm' | 'md' | 'lg' | 'icon-sm' | 'icon-md' | 'icon-lg';
type ToggleRootProps = ComponentProps<typeof TogglePrimitive.Root> & {
  variant?: ToggleVariant;
  size?: ToggleSize;
};

const ToggleRoot = forwardRef<ComponentRef<typeof TogglePrimitive.Root>, ToggleRootProps>(
  function ToggleRoot({ className, variant = 'default', size = 'md', ...props }, ref) {
    return (
      <TogglePrimitive.Root
        ref={ref}
        data-slot="toggle-root"
        data-variant={variant}
        data-size={size}
        className={clsx(styles.root, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const ToggleIndicator = forwardRef<
  ComponentRef<typeof TogglePrimitive.Indicator>,
  ComponentProps<typeof TogglePrimitive.Indicator>
>(function ToggleIndicator({ className, ...props }, ref) {
  return (
    <TogglePrimitive.Indicator
      ref={ref}
      data-slot="toggle-indicator"
      className={clsx(styles.indicator, normalizeClassName(className))}
      {...props}
    />
  );
});

const Toggle = Object.assign(ToggleRoot, {
  Root: ToggleRoot,
  Indicator: ToggleIndicator,
  Context: ToggleContext,
});

export { Toggle, useToggleContext };

@layer moduix.components {
  .root {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--moduix-toggle-content-gap, var(--moduix-spacing-2));
    min-height: var(--moduix-toggle-size-md, var(--moduix-size-md));
    margin: 0;
    border-style: solid;
    border-width: var(--moduix-toggle-border-width, var(--moduix-border-width-sm));
    border-radius: var(--moduix-toggle-radius, var(--moduix-radius-md));
    padding-block: var(--moduix-toggle-padding-y-md, var(--moduix-spacing-1));
    padding-inline: var(--moduix-toggle-padding-x-md, var(--moduix-spacing-4));
    border-color: transparent;
    background-color: transparent;
    color: var(--moduix-toggle-color, var(--moduix-color-foreground));
    appearance: none;
    font: inherit;
    font-size: var(--moduix-toggle-font-size, var(--moduix-text-sm));
    font-weight: var(--moduix-toggle-font-weight, var(--moduix-weight-medium));
    line-height: var(--moduix-toggle-line-height, var(--moduix-line-height-text-sm));
    user-select: none;
    white-space: nowrap;
    cursor: pointer;
    transition:
      background-color var(--moduix-toggle-transition, var(--moduix-transition-default)),
      border-color var(--moduix-toggle-transition, var(--moduix-transition-default)),
      color var(--moduix-toggle-transition, var(--moduix-transition-default)),
      opacity var(--moduix-toggle-transition, var(--moduix-transition-default));

    &:focus-visible {
      outline: var(
          --moduix-toggle-focus-ring-width,
          var(--moduix-focus-ring-width, var(--moduix-border-width-md))
        )
        solid var(--moduix-toggle-focus-ring-color, var(--moduix-color-ring));
      outline-offset: var(--moduix-toggle-focus-ring-offset, var(--moduix-focus-ring-inset-offset));
    }

    &[data-disabled] {
      opacity: var(--moduix-toggle-disabled-opacity, var(--moduix-opacity-disabled));
      cursor: default;
      pointer-events: none;
    }

    & :where(svg) {
      display: block;
      width: var(--moduix-toggle-icon-size, var(--moduix-spacing-4));
      height: var(--moduix-toggle-icon-size, var(--moduix-spacing-4));
      flex-shrink: 0;
    }

    &[data-variant='default'] {
      border-color: var(--moduix-toggle-default-border-color, var(--moduix-color-secondary));
      background-color: var(--moduix-toggle-default-bg, var(--moduix-color-secondary));
      color: var(
        --moduix-toggle-default-color,
        var(--moduix-toggle-color, var(--moduix-color-secondary-foreground))
      );

      @media (hover: hover) {
        &[data-state='off']:not([data-disabled]):hover {
          background-color: var(--moduix-toggle-default-bg-hover, var(--moduix-color-accent));
        }
      }

      &[data-state='off']:not([data-disabled]):active {
        background-color: var(--moduix-toggle-default-bg-active, var(--moduix-color-accent));
      }

      &[data-state='on'] {
        border-color: var(
          --moduix-toggle-default-border-color-pressed,
          var(--moduix-color-primary)
        );
        background-color: var(--moduix-toggle-default-bg-pressed, var(--moduix-color-primary));
        color: var(--moduix-toggle-default-color-pressed, var(--moduix-color-primary-foreground));
      }
    }

    &[data-variant='outline'] {
      border-color: var(--moduix-toggle-outline-border-color, var(--moduix-color-border));
      background-color: var(--moduix-toggle-outline-bg, var(--moduix-color-background));
      color: var(
        --moduix-toggle-outline-color,
        var(--moduix-toggle-color, var(--moduix-color-foreground))
      );

      @media (hover: hover) {
        &[data-state='off']:not([data-disabled]):hover {
          background-color: var(--moduix-toggle-outline-bg-hover, var(--moduix-color-accent));
        }
      }

      &[data-state='off']:not([data-disabled]):active {
        background-color: var(--moduix-toggle-outline-bg-active, var(--moduix-color-accent));
      }

      &[data-state='on'] {
        border-color: var(
          --moduix-toggle-outline-border-color-pressed,
          var(--moduix-color-primary)
        );
        background-color: var(--moduix-toggle-outline-bg-pressed, var(--moduix-color-primary));
        color: var(--moduix-toggle-outline-color-pressed, var(--moduix-color-primary-foreground));
      }
    }

    &[data-variant='ghost'] {
      border-color: var(--moduix-toggle-ghost-border-color, transparent);
      background-color: var(--moduix-toggle-ghost-bg, transparent);
      color: var(
        --moduix-toggle-ghost-color,
        var(--moduix-toggle-color, var(--moduix-color-foreground))
      );

      @media (hover: hover) {
        &[data-state='off']:not([data-disabled]):hover {
          background-color: var(--moduix-toggle-ghost-bg-hover, var(--moduix-color-accent));
        }
      }

      &[data-state='off']:not([data-disabled]):active {
        background-color: var(--moduix-toggle-ghost-bg-active, var(--moduix-color-accent));
      }

      &[data-state='on'] {
        background-color: var(--moduix-toggle-ghost-bg-pressed, var(--moduix-color-accent));
        color: var(--moduix-toggle-ghost-color-pressed, var(--moduix-color-foreground));
      }
    }

    &[data-size='xs'] {
      min-height: var(--moduix-toggle-size-xs, var(--moduix-size-xs));
      padding-block: var(--moduix-toggle-padding-y-xs, var(--moduix-spacing-0-5));
      padding-inline: var(--moduix-toggle-padding-x-xs, var(--moduix-spacing-2-5));
      font-size: var(--moduix-toggle-font-size-xs, var(--moduix-text-xs));
      line-height: var(--moduix-toggle-line-height-xs, var(--moduix-line-height-text-xs));
    }

    &[data-size='sm'] {
      min-height: var(--moduix-toggle-size-sm, var(--moduix-size-sm));
      padding-block: var(--moduix-toggle-padding-y-sm, var(--moduix-spacing-1));
      padding-inline: var(--moduix-toggle-padding-x-sm, var(--moduix-spacing-3));
    }

    &[data-size='lg'] {
      min-height: var(--moduix-toggle-size-lg, var(--moduix-size-lg));
      padding-block: var(--moduix-toggle-padding-y-lg, var(--moduix-spacing-1-5));
      padding-inline: var(--moduix-toggle-padding-x-lg, var(--moduix-spacing-5));
      font-size: var(--moduix-toggle-font-size-lg, var(--moduix-text-md));
      line-height: var(--moduix-toggle-line-height-lg, var(--moduix-line-height-text-md));
    }

    &[data-size='icon-sm'],
    &[data-size='icon-md'],
    &[data-size='icon-lg'] {
      padding: 0;
      gap: 0;
    }

    &[data-size='icon-sm'] {
      width: var(--moduix-toggle-size-icon-sm, var(--moduix-size-sm));
      min-width: var(--moduix-toggle-size-icon-sm, var(--moduix-size-sm));
      height: var(--moduix-toggle-size-icon-sm, var(--moduix-size-sm));
    }

    &[data-size='icon-md'] {
      width: var(--moduix-toggle-size-icon-md, var(--moduix-size-md));
      min-width: var(--moduix-toggle-size-icon-md, var(--moduix-size-md));
      height: var(--moduix-toggle-size-icon-md, var(--moduix-size-md));
    }

    &[data-size='icon-lg'] {
      width: var(--moduix-toggle-size-icon-lg, var(--moduix-size-lg));
      min-width: var(--moduix-toggle-size-icon-lg, var(--moduix-size-lg));
      height: var(--moduix-toggle-size-icon-lg, var(--moduix-size-lg));
    }
  }

  .indicator {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    color: inherit;
  }
}
